--
-- Structure for view `v_daily_stats`
--
DROP TABLE IF EXISTS `v_daily_stats`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u802160697_agrinew`@`%` SQL SECURITY DEFINER VIEW `v_daily_stats`  AS SELECT cast(`json_backup`.`backup_timestamp` as date) AS `tanggal`, count(0) AS `total_sesi`, sum(`json_backup`.`total_records`) AS `total_records`, avg(`json_backup`.`data_size_kb`) AS `avg_size_kb`, avg(cast(replace(`json_backup`.`node_completeness`,'%','') as decimal(5,2))) AS `avg_completeness`, min(`json_backup`.`backup_timestamp`) AS `first_sync`, max(`json_backup`.`backup_timestamp`) AS `last_sync` FROM `json_backup` GROUP BY cast(`json_backup`.`backup_timestamp` as date) ORDER BY cast(`json_backup`.`backup_timestamp` as date) DESC ;

-- --------------------------------------------------------

--
-- Structure for view `v_latest_sessions`
--
DROP TABLE IF EXISTS `v_latest_sessions`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u802160697_agrinew`@`%` SQL SECURITY DEFINER VIEW `v_latest_sessions`  AS SELECT `jb`.`id` AS `id`, `jb`.`sesi_id_getdata` AS `sesi_id_getdata`, `jb`.`total_records` AS `total_records`, `jb`.`node_completeness` AS `node_completeness`, `jb`.`data_size_kb` AS `data_size_kb`, `jb`.`backup_timestamp` AS `backup_timestamp`, `gl`.`waktu_mulai` AS `waktu_mulai`, `gl`.`waktu_selesai` AS `waktu_selesai`, `gl`.`node_sukses` AS `node_sukses`, `gl`.`node_gagal` AS `node_gagal`, timestampdiff(SECOND,`gl`.`waktu_mulai`,`gl`.`waktu_selesai`) AS `duration_seconds` FROM (`json_backup` `jb` left join `getdata_logs` `gl` on(`jb`.`sesi_id_getdata` = `gl`.`sesi_id_getdata`)) ORDER BY `jb`.`id` DESC ;

