--
-- Structure for view `v_node_activity`
--
DROP TABLE IF EXISTS `v_node_activity`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u802160697_agrinew`@`%` SQL SECURITY DEFINER VIEW `v_node_activity`  AS SELECT `nl`.`node_id` AS `node_id`, `n`.`group` AS `group`, `n`.`kode_perlakuan` AS `kode_perlakuan`, count(0) AS `total_logs`, sum(case when `nl`.`status` = 'Aktif' then 1 else 0 end) AS `active_count`, sum(case when `nl`.`status` = 'Non Aktif' then 1 else 0 end) AS `inactive_count`, avg(`nl`.`rssi_dbm`) AS `avg_rssi`, avg(`nl`.`snr_db`) AS `avg_snr`, max(`nl`.`waktu`) AS `last_activity` FROM (`node_logs` `nl` left join `node` `n` on(`nl`.`node_id` = `n`.`node_id`)) WHERE `nl`.`waktu` >= current_timestamp() - interval 7 day GROUP BY `nl`.`node_id`, `n`.`group`, `n`.`kode_perlakuan` ORDER BY `nl`.`node_id` ASC ;

